import React from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import Sidebar from './Sidebar';
import { Search, Moon, Bell, User as UserIcon } from 'lucide-react';

const Layout: React.FC = () => {
  const { user } = useAuth();

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  return (
    <div className="flex h-screen overflow-hidden bg-[#f4f7fe] w-full">
      <Sidebar />
      <div className="flex-1 overflow-auto w-full">
        <header className="sticky top-0 z-10 flex h-20 items-center justify-between px-8 bg-[#f4f7fe]">
          <div className="flex items-center rounded-full bg-white px-4 py-2 shadow-sm w-[400px]">
            <Search className="h-5 w-5 text-gray-400" />
            <input 
              type="text" 
              placeholder="Rechercher IP, Hash, CVE... (Entrée)" 
              className="ml-3 w-full border-none bg-transparent text-sm focus:outline-none text-gray-600"
            />
          </div>

          <div className="flex items-center space-x-6">
            <button className="text-gray-400 hover:text-gray-600">
              <Moon className="h-5 w-5" />
            </button>
            <div className="relative cursor-pointer">
              <Bell className="h-5 w-5 text-gray-400 hover:text-gray-600" />
              <span className="absolute -top-1 -right-1 flex h-3 w-3 items-center justify-center rounded-full bg-red-500 border-2 border-[#f4f7fe]" />
            </div>
            <div className="flex items-center gap-3">
              <div className="text-right">
                <p className="text-sm font-bold text-[#1f2937] leading-none">{user.username}</p>
                <p className="text-[10px] font-bold text-gray-400 uppercase">{user.role}</p>
              </div>
              <div className="flex h-10 w-10 items-center justify-center rounded-full bg-blue-100 text-blue-600 font-bold">
                <UserIcon className="h-5 w-5" />
              </div>
            </div>
          </div>
        </header>

        <main className="p-8 pt-2">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default Layout;
